+import { render, screen } from '@testing-library/react';
+import { createRef } from 'react';
+import { RecentlyViewedCarousel } from './RecentlyViewedCarousel';
+import type { RecentlyViewedProduct } from './RecentlyViewedCarousel';
+
+jest.mock('../Atoms/Carousel', () => ({
+  Carousel: ({ children }: { children: React.ReactNode }) => <div data-testid="carousel">{children}</div>,
+}));
+
+beforeAll(() => {
+  Object.defineProperty(window, 'matchMedia', {
+    writable: true,
+    value: jest.fn((query: string) => ({
+      matches: false,
+      media: query,
+      addEventListener: jest.fn(),
+      removeEventListener: jest.fn(),
+    })),
+  });
+});
+
+const MOCK_PRODUCTS: RecentlyViewedProduct[] = [
+  { id: 1, name: 'Sport-Tek Competitor Polo', linkHref: '/products/polo', imageSrc: 'https://example.com/polo.jpg' },
+  { id: 2, name: 'Bella Canvas V-Neck', linkHref: '/products/vneck', imageSrc: 'https://example.com/vneck.jpg' },
+  { id: 3, name: 'Comfort Colors Tee', linkHref: '/products/tee', imageSrc: 'https://example.com/tee.jpg' },
+];
+
+describe('RecentlyViewedCarousel', () => {
+  it('renders the title', () => {
+    render(<RecentlyViewedCarousel products={MOCK_PRODUCTS} />);
+    expect(screen.getByText('Pick Up Where You Left Off')).toBeInTheDocument();
+  });
+
+  it('renders a custom title', () => {
+    render(<RecentlyViewedCarousel products={MOCK_PRODUCTS} title="Recently viewed items" />);
+    expect(screen.getByText('Recently viewed items')).toBeInTheDocument();
+  });
+
+  it('renders all product cards', () => {
+    render(<RecentlyViewedCarousel products={MOCK_PRODUCTS} />);
+    MOCK_PRODUCTS.forEach((p) => {
+      expect(screen.getByText(p.name)).toBeInTheDocument();
+    });
+  });
+
+  it('renders nothing when products is empty', () => {
+    const { container } = render(<RecentlyViewedCarousel products={[]} />);
+    expect(container.firstChild).toBeNull();
+  });
+
+  it('forwards ref to the root element', () => {
+    const ref = createRef<HTMLDivElement>();
+    render(<RecentlyViewedCarousel products={MOCK_PRODUCTS} ref={ref} />);
+    expect(ref.current).toBeInstanceOf(HTMLDivElement);
+  });
+
+  it('applies custom className', () => {
+    const ref = createRef<HTMLDivElement>();
+    render(<RecentlyViewedCarousel products={MOCK_PRODUCTS} className="custom" ref={ref} />);
+    expect(ref.current?.className).toContain('custom');
+  });
+
+  it('renders data-testid on root', () => {
+    render(<RecentlyViewedCarousel products={MOCK_PRODUCTS} />);
+    expect(screen.getByTestId('recently-viewed-carousel')).toBeInTheDocument();
+  });
+
+  it('renders children below the carousel', () => {
+    render(
+      <RecentlyViewedCarousel products={MOCK_PRODUCTS}>
+        <a href="/all" data-testid="view-all">
+          View All
+        </a>
+      </RecentlyViewedCarousel>,
+    );
+    expect(screen.getByTestId('view-all')).toBeInTheDocument();
+  });
+
+  it('applies large variant class by default', () => {
+    const ref = createRef<HTMLDivElement>();
+    render(<RecentlyViewedCarousel products={MOCK_PRODUCTS} ref={ref} />);
+    expect(ref.current?.className).toContain('large');
+  });
+
+  it('applies compact variant class', () => {
+    const ref = createRef<HTMLDivElement>();
+    render(<RecentlyViewedCarousel products={MOCK_PRODUCTS} variant="compact" ref={ref} />);
+    expect(ref.current?.className).toContain('compact');
+  });
+});
